1	/*
2	 *  yosys -- Yosys Open SYnthesis Suite
3	 *
4	 *  Copyright (C) 2012  Claire Xenia Wolf <claire@yosyshq.com>
5	 *
6	 *  Permission to use, copy, modify, and/or distribute this software for any
7	 *  purpose with or without fee is hereby granted, provided that the above
8	 *  copyright notice and this permission notice appear in all copies.
9	 *
10	 *  THE SOFTWARE IS PROVIDED "AS IS" AND THE AUTHOR DISCLAIMS ALL WARRANTIES
11	 *  WITH REGARD TO THIS SOFTWARE INCLUDING ALL IMPLIED WARRANTIES OF
12	 *  MERCHANTABILITY AND FITNESS. IN NO EVENT SHALL THE AUTHOR BE LIABLE FOR
13	 *  ANY SPECIAL, DIRECT, INDIRECT, OR CONSEQUENTIAL DAMAGES OR ANY DAMAGES
14	 *  WHATSOEVER RESULTING FROM LOSS OF USE, DATA OR PROFITS, WHETHER IN AN
15	 *  ACTION OF CONTRACT, NEGLIGENCE OR OTHER TORTIOUS ACTION, ARISING OUT OF
16	 *  OR IN CONNECTION WITH THE USE OR PERFORMANCE OF THIS SOFTWARE.
17	 *
18	 */
19	
20	#include "kernel/yosys.h"
21	#include "kernel/qcsat.h"
22	#include "kernel/sigtools.h"
23	#include "kernel/modtools.h"
24	#include "kernel/mem.h"
25	#include "kernel/ffinit.h"
26	
27	USING_YOSYS_NAMESPACE
28	PRIVATE_NAMESPACE_BEGIN
29	
30	struct MemoryShareWorker
31	{
32		RTLIL::Design *design;
33		RTLIL::Module *module;
34		SigMap sigmap, sigmap_xmux;
35		ModWalker modwalker;
36		FfInitVals initvals;
37		bool flag_widen;
38		bool flag_sat;
39	
40		// --------------------------------------------------
41		// Consolidate read ports that read the same address
42		// (or close enough to be merged to wide ports)
43		// --------------------------------------------------
44	
45		// A simple function to detect ports that couldn't possibly collide
46		// because of opposite const address bits (simplistic, but enough
47		// to fix problems with inferring wide ports).
48		bool rdwr_can_collide(Mem &mem, int ridx, int widx) {
49			auto &rport = mem.rd_ports[ridx];
50			auto &wport = mem.wr_ports[widx];
51			for (int i = std::max(rport.wide_log2, wport.wide_log2); i < GetSize(rport.addr) && i < GetSize(wport.addr); i++) {
52				if (rport.addr[i] == State::S1 && wport.addr[i] == State::S0)
53					return false;
54				if (rport.addr[i] == State::S0 && wport.addr[i] == State::S1)
55					return false;
56			}
57			return true;
58		}
59	
60		bool merge_rst_value(Mem &mem, Const &res, int wide_log2, const Const &src1, int sub1, const Const &src2, int sub2) {
61			res = Const(State::Sx, mem.width << wide_log2);
62			for (int i = 0; i < GetSize(src1); i++)
63				res.set(i + sub1 * mem.width, src1[i]);
64			for (int i = 0; i < GetSize(src2); i++) {
65				if (src2[i] == State::Sx)
66					continue;
67				int idx = i + sub2 * mem.width;
68				RTLIL::State dst = res[idx];
69				if (dst == src2[i])
70					continue;
71				if (dst != State::Sx)
72					return false;
73				res.set(idx, src2[i]);
74			}
75			return true;
76		}
77	
78		bool consolidate_rd_by_addr(Mem &mem)
79		{
80			if (GetSize(mem.rd_ports) <= 1)
81				return false;
82	
83			log("Consolidating read ports of memory %s.%s by address:\n", module, mem.memid.unescape());
84	
85			bool changed = false;
86			int abits = 0;
87			for (auto &port: mem.rd_ports) {
88				if (GetSize(port.addr) > abits)
89					abits = GetSize(port.addr);
90			}
91			for (int i = 0; i < GetSize(mem.rd_ports); i++)
92			{
93				auto &port1 = mem.rd_ports[i];
94				if (port1.removed)
95					continue;
96				for (int j = i + 1; j < GetSize(mem.rd_ports); j++)
97				{
98					auto &port2 = mem.rd_ports[j];
99					if (port2.removed)
100						continue;
101					if (port1.clk_enable != port2.clk_enable)
102						continue;
103					if (port1.clk_enable) {
104						if (port1.clk != port2.clk)
105							continue;
106						if (port1.clk_polarity != port2.clk_polarity)
107							continue;
108					}
109					if (port1.en != port2.en)
110						continue;
111					if (port1.arst != port2.arst)
112						continue;
113					if (port1.srst != port2.srst)
114						continue;
115					if (port1.ce_over_srst != port2.ce_over_srst)
116						continue;
117					// If the width of the ports doesn't match, they can still be
118					// merged by widening the narrow one.  Check if the conditions
119					// hold for that.
120					int wide_log2 = std::max(port1.wide_log2, port2.wide_log2);
121					SigSpec addr1 = sigmap_xmux(port1.addr);
122					SigSpec addr2 = sigmap_xmux(port2.addr);
123					addr1.extend_u0(abits);
124					addr2.extend_u0(abits);
125					if (GetSize(addr1) <= wide_log2)
126						continue;
127					if (GetSize(addr2) <= wide_log2)
128						continue;
129					if (!addr1.extract(0, wide_log2).is_fully_const())
130						continue;
131					if (!addr2.extract(0, wide_log2).is_fully_const())
132						continue;
133					if (addr1.extract_end(wide_log2) != addr2.extract_end(wide_log2)) {
134						// Incompatible addresses after widening.  Last chance — widen both
135						// ports by one more bit to merge them.
136						if (!flag_widen)
137							continue;
138						wide_log2++;
139						if (addr1.extract_end(wide_log2) != addr2.extract_end(wide_log2))
140							continue;
141						if (!addr1.extract(0, wide_log2).is_fully_const())
142							continue;
143						if (!addr2.extract(0, wide_log2).is_fully_const())
144							continue;
145					}
146					// Combine init/reset values.
147					SigSpec sub1_c = port1.addr.extract(0, wide_log2);
148					log_assert(sub1_c.is_fully_const());
149					int sub1 = sub1_c.as_int();
150					SigSpec sub2_c = port2.addr.extract(0, wide_log2);
151					log_assert(sub2_c.is_fully_const());
152					int sub2 = sub2_c.as_int();
153					Const init_value, arst_value, srst_value;
154					if (!merge_rst_value(mem, init_value, wide_log2, port1.init_value, sub1, port2.init_value, sub2))
155						continue;
156					if (!merge_rst_value(mem, arst_value, wide_log2, port1.arst_value, sub1, port2.arst_value, sub2))
157						continue;
158					if (!merge_rst_value(mem, srst_value, wide_log2, port1.srst_value, sub1, port2.srst_value, sub2))
159						continue;
160					// At this point we are committed to the merge.
161					{
162						log("  Merging ports %d, %d (address %s).\n", i, j, log_signal(port1.addr));
163						port1.addr = addr1;
164						port2.addr = addr2;
165						mem.prepare_rd_merge(i, j, &initvals);
166						mem.widen_prep(wide_log2);
167						SigSpec new_data = module->addWire(NEW_ID, mem.width << wide_log2);
168						module->connect(port1.data, new_data.extract(sub1 * mem.width, mem.width << port1.wide_log2));
169						module->connect(port2.data, new_data.extract(sub2 * mem.width, mem.width << port2.wide_log2));
170						for (int k = 0; k < wide_log2; k++)
171							port1.addr[k] = State::S0;
172						port1.init_value = init_value;
173						port1.arst_value = arst_value;
174						port1.srst_value = srst_value;
175						port1.wide_log2 = wide_log2;
176						port1.data = new_data;
177						port2.removed = true;
178						changed = true;
179					}
180				}
181			}
182	
183			if (changed)
184				mem.emit();
185	
186			return changed;
187		}
188	
189	
190		// ------------------------------------------------------
191		// Consolidate write ports that write to the same address
192		// (or close enough to be merged to wide ports)
193		// ------------------------------------------------------
194	
195		bool consolidate_wr_by_addr(Mem &mem)
196		{
197			if (GetSize(mem.wr_ports) <= 1)
198				return false;
199	
200			log("Consolidating write ports of memory %s.%s by address:\n", module, mem.memid.unescape());
201	
202			bool changed = false;
203			int abits = 0;
204			for (auto &port: mem.wr_ports) {
205				if (GetSize(port.addr) > abits)
206					abits = GetSize(port.addr);
207			}
208			for (int i = 0; i < GetSize(mem.wr_ports); i++)
209			{
210				auto &port1 = mem.wr_ports[i];
211				if (port1.removed)
212					continue;
213				if (!port1.clk_enable)
214					continue;
215				for (int j = i + 1; j < GetSize(mem.wr_ports); j++)
216				{
217					auto &port2 = mem.wr_ports[j];
218					if (port2.removed)
219						continue;
220					if (!port2.clk_enable)
221						continue;
222					if (port1.clk != port2.clk)
223						continue;
224					if (port1.clk_polarity != port2.clk_polarity)
225						continue;
226					// If the width of the ports doesn't match, they can still be
227					// merged by widening the narrow one.  Check if the conditions
228					// hold for that.
229					int wide_log2 = std::max(port1.wide_log2, port2.wide_log2);
230					SigSpec addr1 = sigmap_xmux(port1.addr);
231					SigSpec addr2 = sigmap_xmux(port2.addr);
232					addr1.extend_u0(abits);
233					addr2.extend_u0(abits);
234					if (GetSize(addr1) <= wide_log2)
235						continue;
236					if (GetSize(addr2) <= wide_log2)
237						continue;
238					if (!addr1.extract(0, wide_log2).is_fully_const())
239						continue;
240					if (!addr2.extract(0, wide_log2).is_fully_const())
241						continue;
242					if (addr1.extract_end(wide_log2) != addr2.extract_end(wide_log2)) {
243						// Incompatible addresses after widening.  Last chance — widen both
244						// ports by one more bit to merge them.
245						if (!flag_widen)
246							continue;
247						wide_log2++;
248						if (addr1.extract_end(wide_log2) != addr2.extract_end(wide_log2))
249							continue;
250						if (!addr1.extract(0, wide_log2).is_fully_const())
251							continue;
252						if (!addr2.extract(0, wide_log2).is_fully_const())
253							continue;
254					}
255					log("  Merging ports %d, %d (address %s).\n", i, j, log_signal(addr1));
256					port1.addr = addr1;
257					port2.addr = addr2;
258					mem.prepare_wr_merge(i, j, &initvals);
259					mem.widen_wr_port(i, wide_log2);
260					mem.widen_wr_port(j, wide_log2);
261					int pos = 0;
262					while (pos < GetSize(port1.data)) {
263						int epos = pos;
264						while (epos < GetSize(port1.data) && port1.en[epos] == port1.en[pos] && port2.en[epos] == port2.en[pos])
265							epos++;
266						int width = epos - pos;
267						SigBit new_en;
268						if (port2.en[pos] == State::S0) {
269							new_en = port1.en[pos];
270						} else if (port1.en[pos] == State::S0) {
271							port1.data.replace(pos, port2.data.extract(pos, width));
272							new_en = port2.en[pos];
273						} else {
274							port1.data.replace(pos, module->Mux(NEW_ID, port1.data.extract(pos, width), port2.data.extract(pos, width), port2.en[pos]));
275							new_en = module->Or(NEW_ID, port1.en[pos], port2.en[pos]);
276						}
277						for (int k = pos; k < epos; k++)
278							port1.en[k] = new_en;
279						pos = epos;
280					}
281					changed = true;
282					port2.removed = true;
283				}
284			}
285	
286			if (changed)
287				mem.emit();
288	
289			return changed;
290		}
291	
292	
293		// --------------------------------------------------------
294		// Consolidate write ports using sat-based resource sharing
295		// --------------------------------------------------------
296	
297		void consolidate_wr_using_sat(Mem &mem)
298		{
299			if (GetSize(mem.wr_ports) <= 1)
300				return;
301	
302			// Get a list of ports that have any chance of being mergeable.
303	
304			pool<int> eligible_ports;
305	
306			for (int i = 0; i < GetSize(mem.wr_ports); i++) {
307				auto &port = mem.wr_ports[i];
308				std::vector<RTLIL::SigBit> bits = modwalker.sigmap(port.en);
309				for (auto bit : bits)
310					if (bit == RTLIL::State::S1)
311						goto port_is_always_active;
312				eligible_ports.insert(i);
313			port_is_always_active:;
314			}
315	
316			if (eligible_ports.size() <= 1)
317				return;
318	
319			log("Consolidating write ports of memory %s.%s using sat-based resource sharing:\n", module, mem.memid.unescape());
320	
321			// Group eligible ports by clock domain and width.
322	
323			pool<int> checked_ports;
324			std::vector<std::vector<int>> groups;
325			for (int i = 0; i < GetSize(mem.wr_ports); i++)
326			{
327				auto &port1 = mem.wr_ports[i];
328				if (!eligible_ports.count(i))
329					continue;
330				if (checked_ports.count(i))
331					continue;
332	
333				std::vector<int> group;
334				group.push_back(i);
335	
336				for (int j = i + 1; j < GetSize(mem.wr_ports); j++)
337				{
338					auto &port2 = mem.wr_ports[j];
339					if (!eligible_ports.count(j))
340						continue;
341					if (checked_ports.count(j))
342						continue;
343					if (port1.clk_enable != port2.clk_enable)
344						continue;
345					if (port1.clk_enable) {
346						if (port1.clk != port2.clk)
347							continue;
348						if (port1.clk_polarity != port2.clk_polarity)
349							continue;
350					}
351					if (port1.wide_log2 != port2.wide_log2)
352						continue;
353					group.push_back(j);
354				}
355	
356				for (auto j : group)
357					checked_ports.insert(j);
358	
359				if (group.size() <= 1)
360					continue;
361	
362				groups.push_back(group);
363			}
364	
365			bool changed = false;
366			for (auto &group : groups) {
367				auto &some_port = mem.wr_ports[group[0]];
368				string ports;
369				for (auto idx : group) {
370					if (idx != group[0])
371						ports += ", ";
372					ports += std::to_string(idx);
373				}
374				if (!some_port.clk_enable) {
375					log("  Checking unclocked group, width %d: ports %s.\n", mem.width << some_port.wide_log2, ports);
376				} else {
377					log("  Checking group clocked with %sedge %s, width %d: ports %s.\n", some_port.clk_polarity ? "pos" : "neg", log_signal(some_port.clk), mem.width << some_port.wide_log2, ports);
378				}
379	
380				// Okay, time to actually run the SAT solver.
381	
382				QuickConeSat qcsat(modwalker);
383	
384				// create SAT representation of common input cone of all considered EN signals
385	
386				dict<int, int> port_to_sat_variable;
387	
388				for (auto idx : group)
389					port_to_sat_variable[idx] = qcsat.ez->expression(qcsat.ez->OpOr, qcsat.importSig(mem.wr_ports[idx].en));
390	
391				qcsat.prepare();
392	
393				log("  Common input cone for all EN signals: %d cells.\n", GetSize(qcsat.imported_cells));
394	
395				log("  Size of unconstrained SAT problem: %d variables, %d clauses\n", qcsat.ez->numCnfVariables(), qcsat.ez->numCnfClauses());
396	
397				// now try merging the ports.
398	
399				for (int ii = 0; ii < GetSize(group); ii++) {
400					int idx1 = group[ii];
401					auto &port1 = mem.wr_ports[idx1];
402					if (port1.removed)
403						continue;
404					for (int jj = ii + 1; jj < GetSize(group); jj++) {
405						int idx2 = group[jj];
406						auto &port2 = mem.wr_ports[idx2];
407						if (port2.removed)
408							continue;
409	
410						if (qcsat.ez->solve(port_to_sat_variable.at(idx1), port_to_sat_variable.at(idx2))) {
411							log("  According to SAT solver sharing of port %d with port %d is not possible.\n", idx1, idx2);
412							continue;
413						}
414	
415						log("  Merging port %d into port %d.\n", idx2, idx1);
416						mem.prepare_wr_merge(idx1, idx2, &initvals);
417						port_to_sat_variable.at(idx1) = qcsat.ez->OR(port_to_sat_variable.at(idx1), port_to_sat_variable.at(idx2));
418	
419						RTLIL::SigSpec last_addr = port1.addr;
420						RTLIL::SigSpec last_data = port1.data;
421						std::vector<RTLIL::SigBit> last_en = modwalker.sigmap(port1.en);
422	
423						RTLIL::SigSpec this_addr = port2.addr;
424						RTLIL::SigSpec this_data = port2.data;
425						std::vector<RTLIL::SigBit> this_en = modwalker.sigmap(port2.en);
426	
427						RTLIL::SigBit this_en_active = module->ReduceOr(NEW_ID, this_en);
428	
429						if (GetSize(last_addr) < GetSize(this_addr))
430							last_addr.extend_u0(GetSize(this_addr));
431						else
432							this_addr.extend_u0(GetSize(last_addr));
433	
434						SigSpec new_addr = module->Mux(NEW_ID, last_addr.extract_end(port1.wide_log2), this_addr.extract_end(port1.wide_log2), this_en_active);
435	
436						port1.addr = SigSpec({new_addr, port1.addr.extract(0, port1.wide_log2)});
437						port1.data = module->Mux(NEW_ID, last_data, this_data, this_en_active);
438	
439						std::map<std::pair<RTLIL::SigBit, RTLIL::SigBit>, int> groups_en;
440						RTLIL::SigSpec grouped_last_en, grouped_this_en, en;
441						RTLIL::Wire *grouped_en = module->addWire(NEW_ID, 0);
442	
443						for (int j = 0; j < int(this_en.size()); j++) {
444							std::pair<RTLIL::SigBit, RTLIL::SigBit> key(last_en[j], this_en[j]);
445							if (!groups_en.count(key)) {
446								grouped_last_en.append(last_en[j]);
447								grouped_this_en.append(this_en[j]);
448								groups_en[key] = grouped_en->width;
449								grouped_en->width++;
450							}
451							en.append(RTLIL::SigSpec(grouped_en, groups_en[key]));
452						}
453	
454						module->addMux(NEW_ID, grouped_last_en, grouped_this_en, this_en_active, grouped_en);
455						port1.en = en;
456	
457						port2.removed = true;
458						changed = true;
459					}
460				}
461			}
462	
463			if (changed)
464				mem.emit();
465		}
466	
467	
468		// -------------
469		// Setup and run
470		// -------------
471	
472		MemoryShareWorker(RTLIL::Design *design, bool flag_widen, bool flag_sat) : design(design), modwalker(design), flag_widen(flag_widen), flag_sat(flag_sat) {}
473	
474		void operator()(RTLIL::Module* module)
475		{
476			std::vector<Mem> memories = Mem::get_selected_memories(module);
477	
478			this->module = module;
479			sigmap.set(module);
480			initvals.set(&sigmap, module);
481	
482			sigmap_xmux = sigmap;
483			for (auto cell : module->cells())
484			{
485				if (cell->type == ID($mux))
486				{
487					RTLIL::SigSpec sig_a = sigmap_xmux(cell->getPort(ID::A));
488					RTLIL::SigSpec sig_b = sigmap_xmux(cell->getPort(ID::B));
489	
490					if (sig_a.is_fully_undef())
491						sigmap_xmux.add(cell->getPort(ID::Y), sig_b);
492					else if (sig_b.is_fully_undef())
493						sigmap_xmux.add(cell->getPort(ID::Y), sig_a);
494				}
495			}
496	
497			for (auto &mem : memories) {
498				while (consolidate_rd_by_addr(mem));
499				while (consolidate_wr_by_addr(mem));
500			}
501	
502			if (!flag_sat)
503				return;
504	
505			modwalker.setup(module);
506	
507			for (auto &mem : memories)
508				consolidate_wr_using_sat(mem);
509		}
510	};
511	
512	struct MemorySharePass : public Pass {
513		MemorySharePass() : Pass("memory_share", "consolidate memory ports") { }
514		void help() override
515		{
516			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
517			log("\n");
518			log("    memory_share [-nosat] [-nowiden] [selection]\n");
519			log("\n");
520			log("This pass merges share-able memory ports into single memory ports.\n");
521			log("\n");
522			log("The following methods are used to consolidate the number of memory ports:\n");
523			log("\n");
524			log("  - When multiple write ports access the same address then this is converted\n");
525			log("    to a single write port with a more complex data and/or enable logic path.\n");
526			log("\n");
527			log("  - When multiple read or write ports access adjacent aligned addresses, they\n");
528			log("    are merged to a single wide read or write port.  This transformation can be\n");
529			log("    disabled with the \"-nowiden\" option.\n");
530			log("\n");
531			log("  - When multiple write ports are never accessed at the same time (a SAT\n");
532			log("    solver is used to determine this), then the ports are merged into a single\n");
533			log("    write port.  This transformation can be disabled with the \"-nosat\" option.\n");
534			log("\n");
535			log("Note that in addition to the algorithms implemented in this pass, the $memrd\n");
536			log("and $memwr cells are also subject to generic resource sharing passes (and other\n");
537			log("optimizations) such as \"share\" and \"opt_merge\".\n");
538			log("\n");
539		}
540		void execute(std::vector<std::string> args, RTLIL::Design *design) override {
541			bool flag_widen = true;
542			bool flag_sat = true;
543			log_header(design, "Executing MEMORY_SHARE pass (consolidating $memrd/$memwr cells).\n");
544			size_t argidx;
545			for (argidx = 1; argidx < args.size(); argidx++)
546			{
547				if (args[argidx] == "-nosat")
548				{
549					flag_sat = false;
550					continue;
551				}
552				if (args[argidx] == "-nowiden")
553				{
554					flag_widen = false;
555					continue;
556				}
557				break;
558			}
559			extra_args(args, argidx, design);
560			MemoryShareWorker msw(design, flag_widen, flag_sat);
561	
562			for (auto module : design->selected_modules()) {
563				if (module->has_processes_warn())
564					continue;
565	
566				msw(module);
567			}
568		}
569	} MemorySharePass;
570	
571	PRIVATE_NAMESPACE_END
